#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_CITY_COUNT 100
#define MAX_FLIGHT_COUNT 5000
#define MAX_PRICE 10000
#define MAX_STOPS 100

// Define the structure for a flight
typedef struct {
    int sourceCity;
    int destinationCity;
    int price;
} Flight;

// Define the structure for a city
typedef struct {
    int city;
    int cost;
    int stops;
} City;

// Compare function for the priority queue
int compare(const void *a, const void *b) {
    City *cityA = (City *)a;
    City *cityB = (City *)b;
    if (cityA->cost < cityB->cost) return -1;
    if (cityA->cost > cityB->cost) return 1;
    return 0;
}

// Function to find the lowest flight cost
int findLowestFlightCost(int cityCount, Flight *flightList, int flightCount, int sourceCity, int destinationCity, int maxStops) {
    // Create a graph from the flight list
    int **graph = (int **)malloc(cityCount * sizeof(int *));
    for (int i = 0; i < cityCount; i++) {
        graph[i] = (int *)malloc(cityCount * sizeof(int));
        for (int j = 0; j < cityCount; j++) {
            graph[i][j] = -1;
        }
    }
    for (int i = 0; i < flightCount; i++) {
        graph[flightList[i].sourceCity][flightList[i].destinationCity] = flightList[i].price;
    }

    // Create a priority queue to store the cities to visit
    City *priorityQueue = (City *)malloc(cityCount * sizeof(City));
    int priorityQueueSize = 0;

    // Add the source city to the priority queue
    priorityQueue[priorityQueueSize].city = sourceCity;
    priorityQueue[priorityQueueSize].cost = 0;
    priorityQueue[priorityQueueSize].stops = 0;
    priorityQueueSize++;

    // Loop until the priority queue is empty
    while (priorityQueueSize > 0) {
        // Sort the priority queue
        qsort(priorityQueue, priorityQueueSize, sizeof(City), compare);

        // Get the city with the minimum cost
        City currentCity = priorityQueue[0];
        priorityQueueSize--;
        for (int i = 0; i < priorityQueueSize; i++) {
            priorityQueue[i] = priorityQueue[i + 1];
        }

        // If the current city is the destination city, return the cost
        if (currentCity.city == destinationCity) {
            return currentCity.cost;
        }

        // If the number of stops exceeds the maximum, skip this city
        if (currentCity.stops > maxStops) {
            continue;
        }

        // Add the neighboring cities to the priority queue
        for (int i = 0; i < cityCount; i++) {
            if (graph[currentCity.city][i] != -1) {
                City newCity;
                newCity.city = i;
                newCity.cost = currentCity.cost + graph[currentCity.city][i];
                newCity.stops = currentCity.stops + 1;
                priorityQueue[priorityQueueSize] = newCity;
                priorityQueueSize++;
            }
        }
    }

    // If no path is found, return -1
    return -1;
}

