    bool operator()(const City &a, const City &b) {
        return a.cost > b.cost;
    }
};

// Function to find the lowest flight cost
int findLowestFlightCost(int cityCount, vector<Flight> &flightList, int sourceCity, int destinationCity, int maxStops) {
    // Create a graph from the flight list
    vector<vector<int>> graph(cityCount, vector<int>(cityCount, -1));
    for (int i = 0; i < flightList.size(); i++) {
        graph[flightList[i].sourceCity][flightList[i].destinationCity] = flightList[i].price;
    }

    // Create a priority queue to store the cities to visit
    priority_queue<City, vector<City>, compare> priorityQueue;

    // Add the source city to the priority queue
    City currentCity;
    currentCity.city = sourceCity;
    currentCity.cost = 0;
    currentCity.stops = 0;
    priorityQueue.push(currentCity);

    // Loop until the priority queue is empty
    while (!priorityQueue.empty()) {
        // Get the city with the minimum cost
        currentCity = priorityQueue.top();
        priorityQueue.pop();

        // If the current city is the destination city, return the cost
        if (currentCity.city == destinationCity) {
            return currentCity.cost;
        }

        // If the number of stops exceeds the maximum, skip this city
        if (currentCity.stops > maxStops) {
            continue;
        }

        // Add the neighboring cities to the priority queue
        for (int i = 0; i < cityCount; i++) {
            if (graph[currentCity.city][i] != -1) {
                City newCity;
                newCity.city = i;
                newCity.cost = currentCity.cost + graph[currentCity.city][i];
                newCity.stops = currentCity.stops + 1;
                priorityQueue.push(newCity);
            }
        }
    }

    // If no path is found, return -1
