import java.util.PriorityQueue;
import java.util.Comparator;
import java.util.Scanner;

public class Main {
    // Define the structure for a flight
    static class Flight {
        int sourceCity;
        int destinationCity;
        int price;

        public Flight(int sourceCity, int destinationCity, int price) {
            this.sourceCity = sourceCity;
            this.destinationCity = destinationCity;
            this.price = price;
        }
    }

    // Define the structure for a city
    static class City implements Comparable<City> {
        int city;
        int cost;
        int stops;

        public City(int city, int cost, int stops) {
            this.city = city;
            this.cost = cost;
            this.stops = stops;
        }

        @Override
        public int compareTo(City other) {
            return Integer.compare(this.cost, other.cost);
        }
    }

    // Function to find the lowest flight cost
    public static int findLowestFlightCost(int cityCount, Flight[] flightList, int sourceCity, int destinationCity, int maxStops) {
        // Create a graph from the flight list
        int[][] graph = new int[cityCount][cityCount];
        for (int i = 0; i < cityCount; i++) {
            for (int j = 0; j < cityCount; j++) {
                graph[i][j] = -1;
            }
        }
        for (int i = 0; i < flightList.length; i++) {
            graph[flightList[i].sourceCity][flightList[i].destinationCity] = flightList[i].price;
        }

        // Create a priority queue to store the cities to visit
        PriorityQueue<City> priorityQueue = new PriorityQueue<>();

        // Add the source city to the priority queue
        City currentCity = new City(sourceCity, 0, 0);
        priorityQueue.add(currentCity);

        // Loop until the priority queue is empty
        while (!priorityQueue.isEmpty()) {
            // Get the city with the minimum cost
            currentCity = priorityQueue.poll();

            // If the current city is the destination city, return the cost
            if (currentCity.city == destinationCity) {
                return currentCity.cost;
            }

            // If the number of stops exceeds the maximum, skip this city
            if (currentCity.stops > maxStops) {
                continue;
            }

            // Add the neighboring cities to the priority queue
            for (int i = 0; i < cityCount; i++) {
                if (graph[currentCity.city][i] != -1) {
                    City newCity = new City(i, currentCity.cost + graph[currentCity.city][i], currentCity.stops + 1);
                    priorityQueue.add(newCity);
                }
            }
        }

        // If no path is found, return -1
        return -1;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int cityCount = scanner.nextInt();
            Flight[] flightList = new Flight[cityCount * cityCount];
            int flightCount = 0;
            for (int i = 0; i < cityCount; i++) {
                for (int j = 0; j < cityCount; j++) {
                    int price = scanner.nextInt();
                    if (price != -1) {
                        flightList[flightCount] = new Flight(i, j, price);
                        flightCount++;
                    }
                }
            }
            int sourceCity = scanner.nextInt();
            int destinationCity = scanner.nextInt();
            int maxStops = scanner.nextInt();
            int lowestCost = findLowestFlightCost(cityCount, flightList, sourceCity, destinationCity, maxStops);
            System.out.println(lowestCost);
        }
    }
}
